const rows = $input.all().map(r => r.json);
const count = rows.length;

const emails = rows.map(r => ({
  id: r.id,
  emailId: r.email_id,
  threadId: r.thread_id,
  from: r.from_address,
  to: r.to_address,
  subject: r.subject,
  bodyPreview: r.body_preview,
  hasAttachments: r.has_attachments,
  classification: r.classification,
  suggestedReply: {
    subject: r.reply_subject,
    bodyText: r.reply_body,
    bodyHtml: r.reply_html,
    confidence: r.reply_confidence
  },
  source: r.source,
  tokensUsed: r.tokens_used,
  receivedAt: r.created_at,
  replyGeneratedAt: r.reply_generated_at
}));

return [{ json: { success: true, data: { count, emails } } }];

const body = $input.first().json.body || $input.first().json;
const incomingLogId = body.incomingLogId;
const tenantId = body.tenantId;
const action = body.action; // 'approve', 'edit_and_send', 'reject'
const editedSubject = body.editedSubject || null;
const editedBody = body.editedBody || null;
const editedHtml = body.editedHtml || null;

if (!incomingLogId || !tenantId || !action) {
  return [{ json: { success: false, error: 'incomingLogId, tenantId et action requis' } }];
}

return [{ json: {
  incomingLogId, tenantId, action,
  editedSubject, editedBody, editedHtml,
  valid: true
} }];

const action = $('11. Valider action').first().json;
const emailLog = $input.first().json;

const subject = action.editedSubject || emailLog.reply_subject;
const bodyText = action.editedBody || emailLog.reply_body;
const bodyHtml = action.editedHtml || emailLog.reply_html;
const to = emailLog.from_address;

return [{ json: {
  ...action,
  to,
  replySubject: subject,
  replyText: bodyText,
  replyHtml: bodyHtml,
  emailLog
} }];

const action = $('13. Preparer action').first().json;
const finalAction = action.action === 'reject' ? 'rejected' : 'sent_approved';

return [{ json: {
  success: true,
  data: {
    incomingLogId: action.incomingLogId,
    action: finalAction,
    to: action.to,
    subject: action.replySubject
  }
} }];
